CREATE TYPE "IranKetabImportStatus" AS ENUM ('CREATED','EXTRACTING','PREVIEW_READY','DRAFT_REVIEW','COVER_PREPARATION','READY_TO_COMMIT','COMMITTING','SUCCESS','FAILED','CANCELLED');
CREATE TYPE "IranKetabImportEventType" AS ENUM ('SESSION_CREATED','EXTRACTION_STARTED','EXTRACTION_COMPLETED','DRAFT_SAVED','COVER_PREPARATION_STARTED','COVER_PREPARATION_COMPLETED','COMMIT_STARTED','COMMIT_COMPLETED','COMMIT_FAILED');
CREATE TABLE "IranKetabImportSession" ("id" varchar PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, "admin_id" varchar NOT NULL REFERENCES "User"("id") ON DELETE restrict, "source_url" text NOT NULL, "canonical_source_url" text NOT NULL, "source_name" text DEFAULT 'iranketab' NOT NULL, "status" "IranKetabImportStatus" DEFAULT 'CREATED' NOT NULL, "started_at" timestamp, "completed_at" timestamp, "draft_version" integer DEFAULT 1 NOT NULL, "catalog_id" varchar REFERENCES "CatalogBook"("id") ON DELETE set null, "draft" jsonb, "extraction" jsonb, "extraction_fingerprint" text, "prepared_covers" jsonb, "result_summary" jsonb, "error_code" text, "error_message" text, "retryable" boolean DEFAULT false NOT NULL, "metadata" jsonb, "created_at" timestamp DEFAULT now() NOT NULL, "updated_at" timestamp DEFAULT now() NOT NULL);
CREATE TABLE "IranKetabImportEvent" ("id" varchar PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, "session_id" varchar NOT NULL REFERENCES "IranKetabImportSession"("id") ON DELETE cascade, "type" "IranKetabImportEventType" NOT NULL, "metadata" jsonb, "created_at" timestamp DEFAULT now() NOT NULL);
CREATE INDEX "IranKetabImportSession_admin_idx" ON "IranKetabImportSession" ("admin_id"); CREATE INDEX "IranKetabImportSession_status_idx" ON "IranKetabImportSession" ("status"); CREATE INDEX "IranKetabImportSession_created_idx" ON "IranKetabImportSession" ("created_at"); CREATE INDEX "IranKetabImportSession_canonical_idx" ON "IranKetabImportSession" ("canonical_source_url");
CREATE INDEX "IranKetabImportEvent_session_idx" ON "IranKetabImportEvent" ("session_id"); CREATE INDEX "IranKetabImportEvent_created_idx" ON "IranKetabImportEvent" ("created_at"); CREATE INDEX "IranKetabImportEvent_type_idx" ON "IranKetabImportEvent" ("type");
